// app/(creator)/plans/page.tsx
"use client"

import { useState } from "react"
import { Button } from "@/components/ui/Button"
import { Input, SectionLabel, SidebarItem, Textarea } from "@/components/ui/hubora-ui"
import { cn } from "@/lib/utils"

const INITIAL_PLANS = [
  {
    id: "basic",
    name: "Basic",
    price: "1000",
    description: "Perfect for casual followers who want the essentials.",
    features: ["All free posts", "Community comments", "Monthly newsletter"],
    subscribers: 890,
    active: true,
  },
  {
    id: "pro",
    name: "Pro",
    price: "2500",
    description: "Full access for the dedicated fan. All content, no limits.",
    features: ["Everything in Basic", "All video content", "Early access", "Discord community"],
    subscribers: 1020,
    active: true,
    featured: true,
  },
  {
    id: "vip",
    name: "VIP",
    price: "5000",
    description: "The inner circle. Direct access and exclusive perks.",
    features: ["Everything in Pro", "1-on-1 monthly session", "Downloadable assets", "Name in credits"],
    subscribers: 230,
    active: true,
  },
]

export default function CreatorPlansPage() {
  const [plans, setPlans] = useState(INITIAL_PLANS)
  const [editing, setEditing] = useState<string | null>(null)
  const [saved, setSaved] = useState<string | null>(null)

  const handleSave = (id: string) => {
    setSaved(id)
    setEditing(null)
    setTimeout(() => setSaved(null), 2000)
  }

  return (
    <div className="flex min-h-screen bg-[#FAFAFA]">

      <main className="flex-1 px-8 py-8 max-w-4xl">

        <div className="flex items-start justify-between mb-8">
          <div>
            <h1 className="font-display text-[24px] font-bold text-[#0F0F14] tracking-tight">Subscription Plans</h1>
            <p className="font-body text-[13px] text-[#9CA3AF] mt-1">Set your pricing and what each tier unlocks</p>
          </div>
          <Button variant="primary" size="md" leftIcon={<span>+</span>}>Add Plan</Button>
        </div>

        {/* Summary strip */}
        <div className="grid grid-cols-3 gap-4 mb-8">
          {plans.map(p => (
            <div key={p.id} className="bg-white rounded-2xl p-5 shadow-[0_0_0_1px_rgba(0,0,0,0.04),0_2px_8px_-2px_rgba(0,0,0,0.06)]">
              <p className="font-body text-[11px] font-semibold uppercase tracking-wider text-[#9CA3AF] mb-1">{p.name}</p>
              <p className="font-display text-[24px] font-bold text-[#0F0F14] leading-none">₦{Number(p.price).toLocaleString()}</p>
              <p className="font-body text-[12px] text-[#9CA3AF] mt-1">/month</p>
              <div className="mt-3 pt-3 border-t border-[#F3F4F6]">
                <p className="font-display font-bold text-[18px] text-[#6C36F5]">{p.subscribers.toLocaleString()}</p>
                <p className="font-body text-[11px] text-[#9CA3AF]">active subscribers</p>
              </div>
            </div>
          ))}
        </div>

        {/* Plan cards */}
        <div className="flex flex-col gap-5">
          {plans.map(plan => (
            <div
              key={plan.id}
              className={cn(
                "bg-white rounded-2xl overflow-hidden shadow-[0_0_0_1px_rgba(0,0,0,0.04),0_2px_8px_-2px_rgba(0,0,0,0.06)]",
                plan.featured && "ring-2 ring-[#6C36F5] ring-offset-2"
              )}
            >
              {/* Plan header */}
              <div className={cn(
                "flex items-center justify-between px-6 py-4 border-b border-[#F3F4F6]",
                plan.featured && "bg-gradient-to-r from-[#F5F3FF] to-white"
              )}>
                <div className="flex items-center gap-3">
                  <h2 className="font-display font-bold text-[17px] text-[#0F0F14]">{plan.name}</h2>
                  {plan.featured && (
                    <span className="bg-[#6C36F5] text-white text-[10px] font-display font-bold uppercase tracking-wider px-2.5 py-1 rounded-full">
                      Most Popular
                    </span>
                  )}
                  {saved === plan.id && (
                    <span className="text-[#10B981] font-body text-[12px] font-medium">✓ Saved</span>
                  )}
                </div>
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setEditing(editing === plan.id ? null : plan.id)}
                  >
                    {editing === plan.id ? "Cancel" : "Edit"}
                  </Button>
                  {editing === plan.id && (
                    <Button variant="primary" size="sm" onClick={() => handleSave(plan.id)}>
                      Save
                    </Button>
                  )}
                </div>
              </div>

              {editing === plan.id ? (
                /* Edit mode */
                <div className="p-6 flex flex-col gap-4">
                  <div className="grid grid-cols-2 gap-4">
                    <Input label="Plan Name" type="text" defaultValue={plan.name} />
                    <Input label="Monthly Price (₦)" type="number" defaultValue={plan.price} />
                  </div>
                  <Textarea label="Description" rows={2} defaultValue={plan.description} />
                  <div>
                    <label className="text-[13px] font-display font-semibold text-[#374151] block mb-2">Features</label>
                    <div className="flex flex-col gap-2">
                      {plan.features.map((f, i) => (
                        <div key={i} className="flex gap-2">
                          <input
                            defaultValue={f}
                            className="flex-1 bg-white border-[1.5px] border-[#E5E7EB] rounded-xl px-4 py-2 text-[13px] font-body outline-none focus:border-[#6C36F5] focus:shadow-[0_0_0_3px_rgba(108,54,245,0.1)] transition-all"
                          />
                          <Button variant="icon" size="icon-sm" className="hover:text-[#EF4444] hover:bg-[#FEF2F2]">✕</Button>
                        </div>
                      ))}
                      <button className="flex items-center gap-2 text-[#6C36F5] font-body text-[12px] font-medium hover:underline underline-offset-2 mt-1">
                        + Add feature
                      </button>
                    </div>
                  </div>
                </div>
              ) : (
                /* View mode */
                <div className="p-6 flex items-start gap-8">
                  <div className="flex-1">
                    <p className="font-display font-bold text-[28px] text-[#0F0F14] leading-none">
                      ₦{Number(plan.price).toLocaleString()}
                      <span className="font-body font-normal text-[14px] text-[#9CA3AF] ml-1">/month</span>
                    </p>
                    <p className="font-body text-[13px] text-[#6B7280] mt-2 leading-relaxed">{plan.description}</p>
                  </div>
                  <div className="flex-1">
                    <p className="font-body text-[11px] font-semibold uppercase tracking-wider text-[#9CA3AF] mb-3">Includes</p>
                    <ul className="flex flex-col gap-2">
                      {plan.features.map((f, i) => (
                        <li key={i} className="flex items-center gap-2.5 font-body text-[13px] text-[#374151]">
                          <span className="text-[#10B981] text-[12px]">✓</span>
                          {f}
                        </li>
                      ))}
                    </ul>
                  </div>
                  <div className="flex flex-col items-end gap-2">
                    <div className={cn(
                      "w-10 h-5 rounded-full transition-all duration-200 relative cursor-pointer",
                      plan.active ? "bg-[#6C36F5]" : "bg-[#E5E7EB]"
                    )}
                      onClick={() => setPlans(plans.map(p => p.id === plan.id ? { ...p, active: !p.active } : p))}
                    >
                      <div className={cn(
                        "absolute top-0.5 w-4 h-4 rounded-full bg-white shadow-sm transition-all duration-200",
                        plan.active ? "left-5" : "left-0.5"
                      )} />
                    </div>
                    <p className="font-body text-[11px] text-[#9CA3AF]">{plan.active ? "Active" : "Paused"}</p>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* Payout info */}
        <div className="mt-8 bg-[#F5F3FF] border border-[#DDD6FE] rounded-2xl p-5 flex items-start gap-4">
          <div className="w-9 h-9 rounded-xl bg-[#EDE9FE] flex items-center justify-center text-[18px] shrink-0">💡</div>
          <div>
            <p className="font-display font-semibold text-[14px] text-[#0F0F14]">Hubora takes 10%</p>
            <p className="font-body text-[13px] text-[#6B7280] mt-0.5 leading-relaxed">
              You keep 90% of all subscription revenue. Payouts are processed every Monday directly to your bank account.
            </p>
          </div>
        </div>

      </main>
    </div>
  )
}

